import{_ as a,o as c,c as o,a3 as r}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Namespace clore::generate::cache","description":"clore::generate::cache 命名空间负责实现生成过程的缓存子系统，通过文件系统持久化存储提示（prompt）与响应（response）的映射，以避免重复计算。其核心数据结构包括 CacheIndex（缓存索引）和 CacheError（错误类型），并围绕它们提供同步与异步操作：load_cache_index / load_cache_index_async 用于从指定路径加载索引，find_cached_response 在索引中查找缓存条目，save_cache_entry / save_cache_entry_async 将新条目持久化。此外，make_prompt_response_cache_key 生成唯一的缓存键，而 normalize_text_for_hashing 对文本进行规范化以保证键的一致性。这些功能共同构成了一个可复用的缓存层，降低了 clore::generate 中模型调用的开销。","frontmatter":{"title":"Namespace clore::generate::cache","description":"clore::generate::cache 命名空间负责实现生成过程的缓存子系统，通过文件系统持久化存储提示（prompt）与响应（response）的映射，以避免重复计算。其核心数据结构包括 CacheIndex（缓存索引）和 CacheError（错误类型），并围绕它们提供同步与异步操作：load_cache_index / load_cache_index_async 用于从指定路径加载索引，find_cached_response 在索引中查找缓存条目，save_cache_entry / save_cache_entry_async 将新条目持久化。此外，make_prompt_response_cache_key 生成唯一的缓存键，而 normalize_text_for_hashing 对文本进行规范化以保证键的一致性。这些功能共同构成了一个可复用的缓存层，降低了 clore::generate 中模型调用的开销。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/generate/cache/index.md","filePath":"zh/clore/namespaces/clore/generate/cache/index.md"}'),t={name:"zh/clore/namespaces/clore/generate/cache/index.md"};function n(d,e,h,s,i,l){return c(),o("div",null,[...e[0]||(e[0]=[r("",74)])])}const _=a(t,[["render",n]]);export{g as __pageData,_ as default};
